// @see io.seata.rb.datasource.ConnectionProxy#processGlobalTransaction Commit
private void processGlobalTransactionCommit() throws SQException {
    try {
        // 1.向TC注册分支事务
            register();
    } catch (TransactionException e) {
        recognizeLockKeyConflictException(e, context.buildLockKeys());
    }
    try {
        // 2.将Undo和Redo日志持久化
        UndoLogFactory.getUndoLogManager(this.getDbType()).flushUndoLogs(
            this);
        // 3.提交分支事务
            targetConnection.commit();
    } catch (Throwable ex) {
        // 4.向TC上报分支事务状态
            report(false);
            throw new SQException(ex);
    }
    if (IS_REPORT_SUCCESS_ENABLE) {
        // 5.向TC上报分支事务状态
            report(true);
    }
    context.reset();
}

